"""
MKT Original Language Commentary — Proverbs chapter 31
Run: python3 scripts/zc-original-proverbs-31-31.py

Source data used:
- data/interlinear/proverbs.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/proverbs.json

Key decisions:
- 31:1 massa could be "oracle" or the place Massa (Gen 25:14, Ishmaelite region);
  the Aramaic bar (son) in 31:2 suggests non-Israelite origin
- 31:10-31 is an acrostic poem — 22 verses, each beginning with successive
  letters of the Hebrew alphabet (aleph through taw)
- eshet chayil (31:10): chayil is warrior-valor, the same word as Boaz's
  epithet (Ruth 2:1) — not merely "good wife" but "woman of valor/strength"
- 31:22: shesh ve'argaman (fine linen and purple) are the tabernacle colors
  (Exod 25:4) — a deliberate echo of the sacred
- 31:26: torat chesed (the law/instruction of chesed) — her speech embodies
  the great covenant virtue
- 31:30: yirat Adonai closes the poem with Proverbs' foundational principle (1:7)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

PROVERBS = {
  "31": {
    "1": "<p><strong>divrei lemuel</strong> — the 'words of Lemuel.' The name means 'belonging to God' or 'for God,' but Lemuel is otherwise unidentified; the Talmud (b. Sanhedrin 70b) identifies him with Solomon, but this is uncertain. <em>Massa</em> (the oracle) is ambiguous: it is the standard prophetic-oracle term (<em>massa</em> = burden/oracle) but also a place name in northern Arabia, home of Ishmael's son Massa (Gen 25:14), suggesting a non-Israelite source. The instruction is female-authored — 'that his mother taught him' — making this one of the Bible's rare explicitly feminine wisdom texts.</p>",
    "2": "<p><strong>bar</strong> — Aramaic for 'son,' repeated three times (<em>mah beri, mah bar bitni, mah bar nedarai</em>). The use of Aramaic <em>bar</em> rather than Hebrew <em>ben</em> throughout these verses reinforces the non-Israelite origin of the text; it is the language of the region east and northeast of Israel. The threefold invocation — son, son of my womb, son of my vows — builds from relational to physical to covenantal: the son was born from her body and dedicated to God before birth.</p>",
    "3": "<p><strong>chelkha</strong> — 'your strength/vigor' (<em>chayil</em> is sometimes used, but here <em>koach</em>-related). The warning 'do not give your strength to women' is a royal-wisdom concern about the drain of royal vitality through sexual excess (cf. Solomon's many wives, 1 Kgs 11:1-8). 'Those who ruin kings' (<em>lemechot melakhim</em>) — literally 'to the blotting out of kings'; the verb <em>machah</em> means to wipe out, destroy. The concern is dynastic and political as well as personal.</p>",
    "4": "<p><strong>lo lemelakhim, lemuel, lo lemelakhim</strong> — the emphatic repetition of prohibition. The doubling of 'not for kings' with the vocative 'O Lemuel' in the middle creates a chiastic intensification: the instruction is applied to this specific king by name. <em>Shekhar</em> (strong drink) is the fermented grain or date beer distinguished from <em>yayin</em> (grape wine); both are prohibited to kings in their governing capacity.</p>",
    "5": "<p><strong>yisheteh veyishkach mechoquaq</strong> — 'he will drink and forget the law/decree.' <em>Mechoquaq</em> is from <em>chaqaq</em>, to engrave or decree; it refers to the established law that the king is responsible to uphold. The judicial concern is explicit: intoxication perverts (<em>yeshaneh</em>, changes/distorts) the judgment (<em>din</em>) of the afflicted (<em>aniyyim</em>). The king's primary judicial role in protecting the vulnerable is the organizing concern of the entire passage.</p>",
    "6": "<p><strong>tenu shekhar le'obed</strong> — 'give strong drink to one who is perishing.' The reversal is deliberate: kings should not drink; the dying and the bitter-souled should. This is a pragmatic prescription for pain management. <em>Obed</em> is the one in extremis — perishing, dying; <em>mare nefesh</em> is 'bitter of soul,' the term used of Hannah (1 Sam 1:10) and Job (3:20). The text does not idealize sobriety for its own sake but redirects it: not for governance, appropriate for those beyond governing.</p>",
    "7": "<p><strong>yishteh veyishkach rish</strong> — 'let him drink and forget his poverty.' <em>Rish</em> is poverty; <em>amal</em> (misery, labor-pain) is the word used in Ecclesiastes for the futile toil of life. The prescription is explicitly palliative — not curative — and is offered with compassion. The passage does not endorse intoxication broadly; it locates it in a specific context of terminal suffering where it serves a humanitarian function.</p>",
    "8": "<p><strong>petach pikha le'illem</strong> — 'open your mouth for the mute.' <em>Illem</em> is the dumb or mute person — literally one who cannot speak in their own defense. 'All who are left desolate' (<em>bene chalof</em>) is unusual: <em>chalof</em> (to pass by, to change) suggests those who are passing away, transient, overlooked — perhaps orphans, immigrants, or the dying. The royal mandate is pure advocacy: to give speech to those who have none.</p>",
    "9": "<p><strong>shaphat tsedeq</strong> — 'judge righteously.' <em>Tsedeq</em> is the characteristic justice-word of the Hebrew legal tradition: righteous, conforming to covenant standard. The parallel objects are 'the poor' (<em>ani</em>) and 'the needy' (<em>evyon</em>) — the two standard categories of the legally vulnerable throughout the prophets and psalms. The Lemuel section ends with the same concern as it opened: the king's fundamental duty is justice, not luxury.</p>",
    "10": "<p><strong>eshet chayil mi yimtsa</strong> — 'a woman of valor — who can find her?' This begins the great acrostic poem (aleph through taw). <em>Chayil</em> is the word for military valor, strength in battle — used of Boaz (Ruth 2:1: <em>ish gibbor chayil</em>, 'a man of great valor'), of warriors (1 Sam 14:52), and of God's angelic host (<em>tseva</em>). The MKT's 'excellent wife' is too domestic; 'woman of valor' captures the martial vigor of <em>chayil</em>. The rhetorical question 'who can find her?' (<em>mi yimtsa</em>) recalls Proverbs' earlier question about wisdom (8:35: 'whoever finds me finds life'); the <em>eshet chayil</em> is personified wisdom's earthly embodiment. 'Her worth far surpasses rubies' (<em>rachaq mipeniinim michrah</em>) — <em>peninim</em> (rubies/corals) is used of wisdom's value in 3:15 and 8:11.</p>",
    "11": "<p><strong>batach bah lev baala</strong> — 'her husband's heart trusts in her fully.' <em>Batach</em> is the covenant trust-word — used of trusting in God (Ps 22:5, 37:3) — here applied to marital trust. This is the deepest relational language the Hebrew vocabulary has. <em>Shalal</em> (shortage/spoil) — 'he will have no shortage of good things' or 'no lack of gain'; the husband's abundance flows from the wife's trustworthiness. The Hebrew is economic: <em>shalal</em> is normally war-plunder; she generates household wealth without warfare.</p>",
    "12": "<p><strong>gemalatthu tov velo ra</strong> — 'she does him good and not evil.' <em>Gamal</em> (to deal out, repay, benefit) is the covenant-reciprocity verb — used of God dealing bountifully with Israel (Ps 103:10, 116:7). Her goodness toward her husband is covenant-loyalty in household form. 'All the days of her life' (<em>kol yeme chayyeha</em>) — the span is complete; this is not occasional goodness but the orientation of an entire life.</p>",
    "13": "<p><strong>darsha tsemer upishtim</strong> — 'she seeks out wool and flax.' <em>Darash</em> (to seek, inquire, investigate) is the active verb of deliberate searching used for seeking God (Ps 34:5, Amos 5:4); applied here to textile materials. Wool and flax are the two primary household textile fibres in the ancient Levant; linen comes from flax, wool from sheep. <em>Vataas bechefets kappeha</em> — 'works willingly with her hands'; <em>chefets</em> is delight or pleasure — she does this with genuine will, not compulsion.</p>",
    "14": "<p><strong>hayeta ke'oniyyot socher</strong> — 'she is like merchant ships.' The merchant ship (<em>oniyyah</em>) is the image of long-range trade across the Mediterranean — Tarshish ships, famous for exotic cargo. The comparison is not merely about bringing food from a distance but about the wife's commercial reach and initiative. This is not a domestic kitchen-keeper but a household CEO with trade networks.</p>",
    "15": "<p><strong>vataqom be'od layla</strong> — 'she rises while it is still dark/night.' The predawn rising is a sign of intense dedication (cf. Ps 57:8, 108:2; 'I will awaken the dawn'). <em>Vatiten teref lebetah</em> — 'she gives prey/food to her household'; <em>teref</em> is literally prey, as of a lion — she 'hunts' for her household. <em>Choq</em> (tasks/portion) — she assigns the prescribed portion to her servant girls; organized management of the household labor force.</p>",
    "16": "<p><strong>zameemah sadeh vatiqachehu</strong> — 'she evaluates a field and buys it.' <em>Zamam</em> means to plan, devise, purpose — she is not an impulsive buyer but a deliberate evaluator. The independent property acquisition is striking in an ancient Near Eastern context: she acts with economic agency, purchasing a field from 'the fruit of her hands' (<em>peri kappeha</em>), her own earnings. She then plants a vineyard — capital investment from personal income.</p>",
    "17": "<p><strong>chagrah be'oz motneiha</strong> — 'she girds her loins with strength.' <em>Chagar</em> (to gird) is the warrior's preparation for battle: 'gird your sword on your thigh' (Ps 45:3); 'gird up your loins' is the readiness command throughout the OT. She prepares for her work as a warrior prepares for battle. <em>Vataamets zero'oteha</em> — 'makes her arms powerful/strong'; <em>amets</em> is the strength verb used of Hezekiah (2 Chr 32:7) and Joshua ('be strong and courageous').</p>",
    "18": "<p><strong>taame ki tov sachrah</strong> — 'she sees/tastes that her trade is profitable.' <em>Taam</em> normally means to taste (as in Ps 34:8 'taste and see that the LORD is good'); here it functions as perception/discernment — she has an intuitive sense of the quality and profitability of her work. <em>Lo yichbeh ballaylah neraha</em> — 'her lamp does not go out at night.' <em>Neroah</em> (her lamp) is both literal (the household lamp kept burning signals prosperity and activity) and metaphorical (the lamp as vitality, cf. Prov 20:27; Job 18:5-6).</p>",
    "19": "<p><strong>yadeha shillecha bakishor</strong> — 'she reaches out her hands to the distaff.' The distaff (<em>kishor</em>) is the rod from which fiber is fed to the spindle; the spindle (<em>pelek</em>) twists the fiber into thread. Both are the standard instruments of household textile production. The verse is the technical center of the poem's economic section — the specific skills that generate the household's textile wealth.</p>",
    "20": "<p><strong>kapah paresah le'ani</strong> — 'she opens her hand to the poor.' <em>Paras</em> (to spread, open) — the outstretched open hand is the gesture of generosity. The verse uses both <em>ani</em> (the poor, the afflicted) and <em>evyon</em> (the needy) — the same two categories the king is commanded to defend in 31:9. What the king is mandated to provide in the public sphere, she provides in the private sphere. Her generosity answers the royal mandate.</p>",
    "21": "<p><strong>lo tire levetah mishsaleg</strong> — 'she has no fear of snow for her household.' <em>Shaleg</em> (snow) is the seasonal threat; 'no fear' (<em>lo tire</em>) is the same <em>yare</em> root as 'fear of the LORD' — she has no fear of weather because she has prepared. 'All her household are clothed in warm garments' (<em>shanim</em> — scarlet/double garments, meaning layered, warm clothing). Her preparation against cold is the practical expression of her fearlessness.</p>",
    "22": "<p><strong>marvaddim aseta lah</strong> — 'she makes her own bed coverings.' <em>Marvaddim</em> is hapax — probably fine woven coverings. <strong>Shesh ve'argaman levushah</strong> — 'her clothing is fine linen and purple.' <em>Shesh</em> (fine linen) and <em>argaman</em> (purple/crimson dye) are the precise materials of the tabernacle curtains and priestly vestments (Exod 25:4, 26:1, 28:5-6). The echo is not coincidental — the woman of valor is clothed in the materials of the sacred; her person is a kind of portable sanctuary. Purple was also the color of royalty; she wears both sacred and royal dignity.</p>",
    "23": "<p><strong>noda basha'arim baala</strong> — 'her husband is known in the gates.' The city gate (<em>sha'ar</em>) is the seat of legal proceedings, commerce, and civic authority — where elders judged and business was transacted (cf. Ruth 4:1-12; Boaz at the gate). The husband's reputation and civic standing are enabled by his wife's household management. He can sit at the gates because she has secured the home front. She is the foundation of his public honor.</p>",
    "24": "<p><strong>sadin aseta vatimkor</strong> — 'she makes linen garments and sells them.' <em>Sadin</em> is a fine linen garment — the same word used in Judg 14:12-13 (Samson's riddle prize). She has moved from household production (31:13-19) to commercial enterprise — manufacturing goods for sale to merchants (<em>konaani</em>, Canaanite traders). The word <em>konaani</em> means both Canaanite and trader/merchant; by the Second Temple period it was the standard term for a merchant.</p>",
    "25": "<p><strong>oz vehadar levushah</strong> — 'strength and honor are her clothing.' <em>Oz</em> (strength) and <em>hadar</em> (honor, splendor, majesty) are divine attributes in Ps 104:1 ('the LORD is clothed with splendor and majesty') and Ps 29:4. She is clothed with what God wears — the acrostic poem ascribes to her the attributes of divine majesty. <em>Vatischaq leyom acharon</em> — 'she faces/laughs at the future'; <em>sachaq</em> (to laugh, to rejoice) in the face of an uncertain future signals the confidence of the one who has prepared fully.</p>",
    "26": "<p><strong>piha pateche bechochmah</strong> — 'she opens her mouth with wisdom.' Her speech is characterized by <em>chochmah</em> (wisdom), the supreme virtue of the book of Proverbs (1:2, 2:2, 4:5-7). But more precisely: <strong>vetorat chesed al leshonah</strong> — 'and the law/instruction of steadfast love is on her tongue.' <em>Torat chesed</em> — literally 'the Torah of chesed.' <em>Chesed</em> is the great covenant-loyalty/steadfast love word — used of God's covenant faithfulness throughout the Psalms and Prophets. Her speech does not merely convey wisdom-rules; it embodies the relational depth of covenant love.</p>",
    "27": "<p><strong>tsofiyyah halichot vetah</strong> — 'she watches over the affairs of her household.' <em>Tsafah</em> (to watch, to keep watch) is the sentinel's verb — used of watchmen on walls (Ps 37:32; Ezek 33:7). She is the household's strategic watchman. <em>Lechem atsut lo tochal</em> — 'she does not eat the bread of idleness'; <em>atsut</em> is sluggishness or idleness — the vice Proverbs condemns repeatedly (6:6-11, 26:14-16). Her watchfulness is the antithesis of the sluggard.</p>",
    "28": "<p><strong>qamu vaneha vayeasheruha</strong> — 'her children rise and call her blessed.' <em>Ashar</em> (to call blessed, to pronounce happy) is related to the <em>ashre</em> ('blessed is the one') formula of the Psalms (Ps 1:1, 32:1). Her children and husband together pronounce her <em>ashre</em>-blessed. <em>Veyehalleluha</em> — 'her husband praises her'; <em>halal</em> (to praise, laud) is the root of <em>hallelujah</em>. The household's liturgical praise of the <em>eshet chayil</em> mirrors the congregation's praise of God.</p>",
    "29": "<p><strong>rabboth banot asu chayil</strong> — 'many women have done excellently/valiantly.' The husband's praise uses <em>chayil</em> again — the valor-word. He is saying: many women have shown valor, but <em>at alit al kullanah</em> — 'you surpass them all.' <em>Alah</em> (to ascend, to surpass) — she has ascended above all others. This is the poem's climactic human assessment before the theological conclusion in 31:30.</p>",
    "30": "<p><strong>sheqer haachen vehevel hayofi</strong> — 'charm is deceptive and beauty is fleeting/vapor.' <em>Sheqer</em> (deception, falsehood) and <em>hevel</em> (vapor, breath, vanity — Ecclesiastes' signature word) — the two qualities that typically secure female social status are both dismissed with the strongest evaluative vocabulary. <strong>Ishah yirat Adonai hi tithallal</strong> — 'a woman who fears the LORD, she is to be praised.' <em>Yirat Adonai</em> is the foundational virtue of all wisdom in Proverbs: 'the fear of the LORD is the beginning of wisdom' (1:7, 9:10). The poem closes by returning the entire portrait of the <em>eshet chayil</em> to its theological foundation: all her valor, industry, generosity, and wisdom flow from the fear of God.</p>",
    "31": "<p><strong>tenu lah miperi yadeiha</strong> — 'give her the fruit of her hands.' The imperative is plural — addressed to the community, the gate, society as a whole: give her what she has earned. <em>Peri yadeiha</em> (fruit of her hands) echoes 31:16 where she buys a field 'from the fruit of her hands' — the hands that produced throughout the poem now receive their just recognition. <strong>Vihalluha basha'arim maaseha</strong> — 'let her works praise her in the gates.' <em>Halal</em> again — the praise-root. The same gates where her husband sits (31:23) now become the venue for her praise. The poem ends where civic life is conducted: her praise is not merely domestic but public, communal, and permanent.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'proverbs')
    merge_comm(existing, PROVERBS)
    save_comm('mkt-original', 'proverbs', existing)
    total = sum(len(v) for v in PROVERBS.values())
    print(f'proverbs mkt-original: wrote {total} verses in ch 31')

if __name__ == '__main__':
    main()
